import { useEffect, useState } from 'react'
import { useParams } from 'react-router-dom'
import { supabase } from '../supabaseClient'

export default function HoSoPrintTemplate() {
    const { id } = useParams()
    const [hoSo, setHoSo] = useState(null)
    const [loading, setLoading] = useState(true)


    useEffect(() => {
        const fetchChiTiet = async () => {
            try {
                const { data, error } = await supabase
                    .from('ho_so')
                    .select('*')
                    .eq('id', id)
                    .single()

                if (error) throw error
                setHoSo(data)
            } catch (error) {
                console.error('L盻擁 t蘯｣i h盻・sﾆ｡ in:', error)
                alert('Khﾃｴng th盻・t蘯｣i d盻ｯ li盻㎡ ﾄ黛ｻ・in!')
            } finally {
                setLoading(false)
            }
        }
        fetchChiTiet()
    }, [id])

    useEffect(() => {
        if (!loading && hoSo) {
            document.title = `HoSo_${hoSo.ho_ten || id}`
        }
    }, [loading, hoSo])

    if (loading) return <div className="text-center p-10">ﾄ紳ng chu蘯ｩn b盻・b蘯｣n in...</div>
    if (!hoSo) return <div className="text-center p-10 text-red-500">Khﾃｴng tﾃｬm th蘯･y d盻ｯ li盻㎡!</div>

    return (

        <div className="bg-gray-100 min-h-screen p-8 print:p-0 print:bg-white print:min-h-0 font-sans text-blue-900 leading-snug">
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Roboto:ital,wght@0,300;0,400;0,500;0,700;1,300;1,400&display=swap');
                @media print {
                    @page {
                        size: A4;
                        margin: 0mm; /* Vi盻］ tr蘯ｯng do padding c盻ｧa div container */
                    }
                    body {
                        font-family: 'Roboto', sans-serif !important;
                        font-size: 10pt;
                        -webkit-print-color-adjust: exact;
                        print-color-adjust: exact;
                        color: #1e3a8a; /* blue-900 */
                    }
                    .print-container {
                        width: 210mm;
                        height: 297mm; /* Force A4 Height */
                        padding: 10mm !important;
                        margin: 0 auto;
                        overflow: hidden !important; /* Prevent page 2 */
                        zoom: 0.95; /* Slight scale down to fit */
                    }
                    /* Ensure body doesn't generate extra pages */
                    html, body { height: 100%; overflow: hidden; }
                        border: 1px solid #e5e7eb;
                    }
                    @media screen {
                        body {
                            min-width: 220mm; /* Force desktop width on mobile */
                            overflow-x: auto;
                        }
                        .print-container {
                            border: 1px solid #e5e7eb;
                            width: 210mm !important;
                            min-width: 210mm !important;
                        }
                    }
                    /* Override tailwind text sizes for fixed print sizes */
                    .text-xs { font-size: 9pt !important; }
                    .text-sm { font-size: 10pt !important; }
                    .text-base { font-size: 11pt !important; }
                    .text-lg { font-size: 12pt !important; }
                    .text-xl { font-size: 14pt !important; }
                    .text-2xl { font-size: 18pt !important; }
                }
            `}</style>

            {/* Toolbar - 蘯ｨn khi in */}
            <div className="fixed top-4 right-4 print:hidden flex gap-2">
                <button
                    onClick={() => window.print()}
                    className="bg-blue-600 text-white px-4 py-2 rounded shadow hover:bg-blue-700 font-sans font-bold flex items-center gap-2 text-sm"
                >
                    <span className="material-icons-outlined text-base">print</span> In Ngay
                </button>
            </div>

            {/* A4 Page Container */}
            <div className="print-container max-w-[210mm] mx-auto bg-white shadow-2xl print:shadow-none print:w-full print:max-w-none p-[15mm] print:p-[15mm] min-h-[297mm]">

                {/* --- HEADER --- */}
                <div className="flex justify-between items-start mb-2 border-b-2 border-blue-900 pb-2">
                    <div className="flex-1">
                        <h1 className="text-2xl font-bold uppercase mb-1">Phi蘯ｿu Thﾃｴng Tin 盻ｨng Viﾃｪn</h1>
                        <p className="text-xs font-semibold italic text-gray-600">JAPAN LABOR SUPPLY APPLICATION FORM</p>
                        <div className="mt-3 flex flex-col gap-2 text-xs">
                            <p className="text-gray-500"><strong>Ngﾃy l蘯ｭp:</strong> {new Date().toLocaleDateString('vi-VN')}</p>

                        </div>
                    </div>
                    <div className="w-[2.4cm] h-[3.2cm] border border-blue-300 overflow-hidden flex items-center justify-center bg-blue-50 ml-4 relative">
                        {hoSo.anh_ho_so ? (
                            <img src={hoSo.anh_ho_so} className="w-full h-full object-cover absolute inset-0" alt="Avatar" />
                        ) : (
                            <span className="text-xs text-center text-gray-400 z-10">蘯｢nh 3x4</span>
                        )}
                    </div>
                </div>

                {/* --- I. THﾃ年G TIN Cﾃ・NHﾃ・ --- */}
                <div className="mb-4">
                    <SectionTitle>I. Thﾃｴng tin cﾃ｡ nhﾃ｢n</SectionTitle>
                    <table className="w-full border-collapse border border-blue-300 text-xs">
                        <tbody>
                            <tr>
                                <td className="border border-blue-300 p-1 font-bold w-32 bg-blue-50">H盻・vﾃ tﾃｪn</td>
                                <td className="border border-blue-300 p-1 uppercase font-bold text-base" colSpan="3">{hoSo.ho_ten}</td>
                            </tr>
                            <tr>
                                <td className="border border-blue-300 p-1 font-bold bg-blue-50">Ngﾃy sinh</td>
                                <td className="border border-blue-300 p-1">{hoSo.ngay_sinh ? new Date(hoSo.ngay_sinh).toLocaleDateString('vi-VN') : ''}</td>
                                <td className="border border-blue-300 p-1 font-bold bg-blue-50 w-20">Gi盻嬖 tﾃｭnh</td>
                                <td className="border border-blue-300 p-1">{hoSo.gioi_tinh}</td>
                            </tr>
                            <tr>
                                <td className="border border-blue-300 p-1 font-bold bg-blue-50">Quﾃｪ quﾃ｡n</td>
                                <td className="border border-blue-300 p-1" colSpan="3">{hoSo.que_quan}</td>
                            </tr>

                            <tr>
                                <td className="border border-blue-300 p-1 font-bold bg-blue-50">Tﾃｴn giﾃ｡o</td>
                                <td className="border border-blue-300 p-1">{hoSo.ton_giao}</td>
                                <td className="border border-blue-300 p-1 font-bold bg-blue-50">Hﾃｴn nhﾃ｢n</td>
                                <td className="border border-blue-300 p-1">{hoSo.hon_nhan}</td>
                            </tr>
                        </tbody>
                    </table>
                </div>

                {/* --- II. S盻ｨC KH盻殺 --- */}
                <div className="mb-4">
                    <SectionTitle>II. S盻ｩc kh盻銃 & Th盻・ch蘯･t</SectionTitle>
                    <table className="w-full border-collapse border border-blue-300 text-xs text-center">
                        <thead>
                            <tr className="bg-blue-50">
                                <th className="border border-blue-300 p-1">Chi盻「 cao</th>
                                <th className="border border-blue-300 p-1">Cﾃ｢n n蘯ｷng</th>
                                <th className="border border-blue-300 p-1">Nhﾃｳm mﾃ｡u</th>
                                <th className="border border-blue-300 p-1">Th盻・l盻ｱc (T/P)</th>
                                <th className="border border-blue-300 p-1">Tay thu蘯ｭn</th>
                                <th className="border border-blue-300 p-1">Mﾃｹ mﾃu</th>
                                <th className="border border-blue-300 p-1">Hﾃｺt thu盻祖</th>
                                <th className="border border-blue-300 p-1">U盻創g rﾆｰ盻｣u</th>
                                <th className="border border-blue-300 p-1">Xﾄノ hﾃｬnh</th>
                            </tr>
                        </thead>
                        <tbody>
                            <tr>
                                <td className="border border-blue-300 p-1 font-bold">{hoSo.chieu_cao} cm</td>
                                <td className="border border-blue-300 p-1 font-bold">{hoSo.can_nang} kg</td>
                                <td className="border border-blue-300 p-1">{hoSo.nhom_mau}</td>
                                <td className="border border-blue-300 p-1">{hoSo.thi_luc_trai}/{hoSo.thi_luc_phai}</td>
                                <td className="border border-blue-300 p-1">{hoSo.tay_thuan}</td>
                                <td className="border border-blue-300 p-1">{formatYesNo(hoSo.mu_mau)}</td>
                                <td className="border border-blue-300 p-1">{formatYesNo(hoSo.hut_thuoc)}</td>
                                <td className="border border-blue-300 p-1">{formatYesNo(hoSo.uong_ruou)}</td>
                                <td className="border border-blue-300 p-1">{formatYesNo(hoSo.xam_hinh)}</td>
                            </tr>
                        </tbody>
                    </table>
                </div>

                {/* --- III. K盻ｸ Nﾄ・G & NGUY盻・ V盻君G (Previously IV) --- */}
                <div className="mb-4">
                    <SectionTitle>III. K盻ｹ nﾄハg & Nguy盻㌻ v盻肱g</SectionTitle>
                    <div className="border border-blue-300 p-2 text-xs flex flex-col gap-1.5">
                        <div className="grid grid-cols-2 gap-4">
                            <p><strong>Ngﾃnh ngh盻・mong mu盻創:</strong> {hoSo.nganh_nghe_mong_muon}</p>
                            <p><strong>Trﾃｬnh ﾄ黛ｻ・Ti蘯ｿng Nh蘯ｭt:</strong> {hoSo.trinh_do_tieng_nhat}</p>
                        </div>
                        <div className="border-t border-dashed border-gray-300 my-1"></div>
                        <div className="grid grid-cols-2 gap-4">
                            <p><strong>ﾄ進盻ノ m蘯｡nh:</strong> {hoSo.diem_manh || '...'}</p>
                            <p><strong>ﾄ進盻ノ y蘯ｿu:</strong> {hoSo.diem_yeu || '...'}</p>
                        </div>
                        <div className="border-t border-dashed border-gray-300 my-1"></div>
                        <div className="grid grid-cols-2 gap-4">
                            <p><strong>B蘯ｱng lﾃ｡i xe:</strong> {hoSo.bang_lai_xe || 'Khﾃｴng'}</p>
                            <p><strong>M盻･c ﾄ妥ｭch ﾄ訴 Nh蘯ｭt:</strong> {hoSo.muc_dich_di_nhat || '...'}</p>
                        </div>
                    </div>
                </div>

                {/* --- IV. GIA ﾄ静君H (Previously III) --- */}
                <div className="mb-4">
                    <SectionTitle>IV. Thﾃnh viﾃｪn gia ﾄ妥ｬnh</SectionTitle>
                    <table className="w-full border-collapse border border-blue-300 text-xs mb-2">
                        <thead>
                            <tr className="bg-blue-50">
                                <th className="border border-blue-300 p-1 w-32">Quan h盻・/th>
                                <th className="border border-blue-300 p-1">H盻・vﾃ tﾃｪn</th>
                                <th className="border border-blue-300 p-1 w-24">Nﾄノ sinh</th>
                                <th className="border border-blue-300 p-1 w-40">Cﾃｴng vi盻㌘</th>
                            </tr>
                        </thead>
                        <tbody>
                            {Array.isArray(hoSo.thong_tin_gia_dinh) && hoSo.thong_tin_gia_dinh.length > 0 ? (
                                hoSo.thong_tin_gia_dinh.map((gd, i) => (
                                    <tr key={i}>
                                        <td className="border border-blue-300 p-1 text-center font-bold">{gd?.quan_he}</td>
                                        <td className="border border-blue-300 p-1 uppercase">{gd?.ho_ten}</td>
                                        <td className="border border-blue-300 p-1 text-center">{gd?.nam_sinh}</td>
                                        <td className="border border-blue-300 p-1">{gd?.nghe_nghiep || gd?.cong_viec}</td>
                                    </tr>
                                ))
                            ) : (
                                <tr><td colSpan="4" className="border border-blue-300 p-1 text-center text-gray-400 italic">Tr盻創g</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* --- V. H盻靴 V蘯､N --- */}
                <div className="mb-4">
                    <SectionTitle>V. Kinh nghi盻㍊ h盻皇 t蘯ｭp</SectionTitle>
                    <table className="w-full border-collapse border border-blue-300 text-xs">
                        <thead>
                            <tr className="bg-blue-50">
                                <th className="border border-blue-300 p-1 w-32">Th盻拱 gian</th>
                                <th className="border border-blue-300 p-1">Trﾆｰ盻拵g h盻皇 / ﾄ脆｡n v盻・ﾄ妥o t蘯｡o</th>
                                <th className="border border-blue-300 p-1 w-40">B蘯ｱng c蘯･p</th>
                            </tr>
                        </thead>
                        <tbody>
                            {Array.isArray(hoSo.qua_trinh_hoc_tap) && hoSo.qua_trinh_hoc_tap.length > 0 ? (
                                hoSo.qua_trinh_hoc_tap.map((h, i) => (
                                    <tr key={i}>
                                        <td className="border border-blue-300 p-1 text-center font-bold">{formatTimeRange(h?.thoi_gian)}</td>
                                        <td className="border border-blue-300 p-1 uppercase">{h?.ten_truong}</td>
                                        <td className="border border-blue-300 p-1 text-center">{h?.bang_cap}</td>
                                    </tr>
                                ))
                            ) : (
                                <tr><td colSpan="3" className="border border-blue-300 p-1 text-center text-gray-400 italic">Tr盻創g</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* --- VI. KINH NGHI盻・ LﾃM VI盻・ --- */}
                <div className="mb-4">
                    <SectionTitle>VI. Kinh nghi盻㍊ lﾃm vi盻㌘</SectionTitle>
                    <table className="w-full border-collapse border border-blue-300 text-xs">
                        <thead>
                            <tr className="bg-blue-50">
                                <th className="border border-blue-300 p-1 w-32">Th盻拱 gian</th>
                                <th className="border border-blue-300 p-1">Tﾃｪn cﾃｴng ty / Nﾆ｡i lﾃm vi盻㌘</th>
                                <th className="border border-blue-300 p-1 w-40">Cﾃｴng vi盻㌘</th>
                            </tr>
                        </thead>
                        <tbody>
                            {Array.isArray(hoSo.kinh_nghiem_lam_viec) && hoSo.kinh_nghiem_lam_viec.length > 0 ? (
                                hoSo.kinh_nghiem_lam_viec.map((k, i) => (
                                    <tr key={i}>
                                        <td className="border border-blue-300 p-1 text-center font-bold">{formatTimeRange(k?.thoi_gian)}</td>
                                        <td className="border border-blue-300 p-1 uppercase">{k?.cong_ty}</td>
                                        <td className="border border-blue-300 p-1 text-center">{k?.cong_viec}</td>
                                    </tr>
                                ))
                            ) : (
                                <tr><td colSpan="3" className="border border-blue-300 p-1 text-center text-gray-400 italic">Tr盻創g</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* --- FOOTER SIGNATURE --- */}
                <div className="mt-2 flex justify-end pr-8">
                    <div className="text-center">
                        <p className="italic text-xs mb-0">............., ngﾃy ..... thﾃ｡ng ..... nﾄノ 20.....</p>
                        <p className="font-bold uppercase text-xs">Ngﾆｰ盻拱 lﾃm ﾄ柁｡n</p>
                        <p className="text-[10px] italic mb-6">(Kﾃｽ vﾃ ghi rﾃｵ h盻・tﾃｪn)</p>
                        <p className="font-bold uppercase text-xs">{hoSo.ho_ten}</p>
                    </div>
                </div>
            </div>
        </div>
    )
}

// --- HELPER COMPONENTS ---
function SectionTitle({ children }) {
    return <h2 className="uppercase font-bold text-xs bg-blue-100 px-2 py-1 mb-2 border border-blue-900 border-l-4 border-l-blue-900 text-blue-900">{children}</h2>
}

function formatTimeRange(rangeString) {
    if (!rangeString) return '---';
    if (!rangeString.includes(' - ')) return rangeString;
    const [start, end] = rangeString.split(' - ');
    const formatDate = (dStr) => {
        if (!dStr) return '?';
        try {
            const d = new Date(dStr);
            if (isNaN(d.getTime())) return dStr;
            return `${d.getMonth() + 1}/${d.getFullYear()}`;
        } catch { return dStr; }
    };
    return `${formatDate(start)} - ${formatDate(end)}`;
}

function formatYesNo(val) {
    if (val === true || val === 'Cﾃｳ') return 'Cﾃｳ';
    if (val === false || val === 'Khﾃｴng') return 'Khﾃｴng';
    return val || 'Khﾃｴng';
}

import { useEffect, useState } from 'react'
import { useParams } from 'react-router-dom'
import { supabase } from '../supabaseClient'
import PrintProfileContentJP from '../components/PrintProfileContentJP'

export default function HoSoPrintTemplateJP() {
    const { id } = useParams()
    const [hoSo, setHoSo] = useState(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchChiTiet = async () => {
            try {
                const { data, error } = await supabase
                    .from('ho_so')
                    .select('*')
                    .eq('id', id)
                    .single()

                if (error) throw error
                setHoSo(data)
            } catch (error) {
                console.error('L盻擁 t蘯｣i h盻・sﾆ｡ in:', error)
                alert('Khﾃｴng th盻・t蘯｣i d盻ｯ li盻㎡ ﾄ黛ｻ・in!')
            } finally {
                setLoading(false)
            }
        }
        fetchChiTiet()
    }, [id])

    useEffect(() => {
        if (!loading && hoSo) {
            document.title = `HoSo_JP_${hoSo.ho_ten || id}`
        }
    }, [loading, hoSo])

    if (loading) return <div className="text-center p-10">Waiting...</div>
    if (!hoSo) return <div className="text-center p-10 text-red-500">Not Found!</div>

    return (
        <div className="bg-gray-100 min-h-screen p-8 print:p-0 print:bg-white print:min-h-0 font-sans text-blue-900 leading-snug">
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Noto+Sans+JP:wght@300;400;500;700&display=swap');
                @media print {
                    @page { size: A4; margin: 0; }
                    html, body {
                        height: 297mm;
                        overflow: hidden;
                    }
                    .print-container {
                        height: 297mm;
                        width: 210mm !important;
                        overflow: hidden !important;
                        zoom: 0.95;
                        padding: 10mm !important;
                        margin: 0 auto !important;
                    }
                    /* Override font/colors */
                    body {
                        font-family: 'Noto Sans JP', sans-serif !important;
                        -webkit-print-color-adjust: exact;
                        print-color-adjust: exact;
                        color: #1e3a8a;
                    }
                }
                @media screen {
                    body {
                        min-width: 220mm;
                        overflow-x: auto;
                    }
                    .print-container {
                        width: 210mm !important;
                        min-width: 210mm !important;
                    }
                }
            `}</style>

            {/* Toolbar - 蘯ｨn khi in */}
            <div className="fixed top-4 right-4 print:hidden flex gap-2 z-50">
                <button
                    onClick={() => window.print()}
                    className="bg-red-600 text-white px-4 py-2 rounded shadow hover:bg-red-700 font-sans font-bold flex items-center gap-2 text-sm"
                >
                    <span className="material-icons-outlined text-base">print</span> 蜊ｰ蛻ｷ (Print JP)
                </button>
            </div>

            <PrintProfileContentJP hoSo={hoSo} />
        </div>
    )
}

