        try {
            const { error } = await supabase.from('lien_ket_don_hang_ho_so').delete().eq('id', linkId)
            if (error) throw error
            await fetchMatchedCandidates()
            if (activeTab === 'add') fetchAvailableCandidates()
        } catch (error) {
            alert('L盻擁 xﾃｳa: ' + error.message)
        }
