                                            ) : matchedCandidates.map(item => (
                                                <tr key={item.id}>
                                                    <td style={{ textAlign: 'center', fontFamily: 'monospace', fontWeight: '800', color: '#059669', fontSize: '0.82rem' }}>{item.sbd}</td>
                                                    <td style={{ padding: '0.4rem 0.4rem' }}>
                                                        <div style={{ width: '30px', height: '30px', borderRadius: '50%', overflow: 'hidden', border: '1px solid #e2e8f0', background: '#f8fafc', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                                            {item.ho_so?.anh_ho_so
                                                                ? <img src={item.ho_so.anh_ho_so} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                                                : <span className="material-icons-outlined" style={{ fontSize: '16px', color: '#cbd5e1' }}>person</span>
                                                            }
                                                        </div>
                                                    </td>
                                                    <td style={{ fontWeight: '700', color: '#0f172a', fontSize: '0.82rem' }}>
                                                        {item.ho_so ? item.ho_so.ho_ten : <span style={{ color: '#f87171', fontStyle: 'italic' }}>D盻ｯ li盻㎡ l盻擁</span>}
                                                    </td>
                                                    <td style={{ textAlign: 'center', fontWeight: '700', fontSize: '0.8rem', color: '#64748b' }}>{age(item.ho_so?.ngay_sinh)}</td>
                                                    <td style={{ fontSize: '0.78rem', color: '#64748b' }}>{item.ho_so?.que_quan || '窶・}</td>
                                                    <td style={{ textAlign: 'center' }}>
                                                        <button onClick={() => handleRemoveCandidate(item.id)}
                                                            style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#fca5a5', padding: '3px', borderRadius: '5px', display: 'flex', alignItems: 'center' }}
                                                            onMouseEnter={e => e.currentTarget.style.color = '#ef4444'}
                                                            onMouseLeave={e => e.currentTarget.style.color = '#fca5a5'}
                                                            title="Xﾃｳa kh盻淑 danh sﾃ｡ch"
                                                        >
                                                            <span className="material-icons-outlined" style={{ fontSize: '16px' }}>cancel</span>
                                                        </button>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}

                            {/* Tab: Thﾃｪm 盻ｩng viﾃｪn */}
                            {activeTab === 'add' && (
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
                                    <div style={{ position: 'relative' }}>
                                        <span className="material-icons-outlined" style={{ position: 'absolute', left: '0.65rem', top: '50%', transform: 'translateY(-50%)', fontSize: '15px', color: '#cbd5e1' }}>search</span>
                                        <input
                                            style={{ width: '100%', paddingLeft: '2.1rem', paddingRight: '1rem', paddingTop: '0.45rem', paddingBottom: '0.45rem', border: '1.5px solid #e2e8f0', borderRadius: '8px', fontSize: '0.8rem', fontFamily: 'inherit', background: '#fff', outline: 'none', boxSizing: 'border-box' }}
                                            placeholder="Tﾃｬm 盻ｩng viﾃｪn theo tﾃｪn... (Enter ﾄ黛ｻ・tﾃｬm)"
                                            value={searchTerm}
                                            onChange={e => setSearchTerm(e.target.value)}
                                            onKeyDown={e => e.key === 'Enter' && fetchAvailableCandidates()}
                                            onFocus={e => e.target.style.borderColor = '#10b981'}
                                            onBlur={e => e.target.style.borderColor = '#e2e8f0'}
                                        />
                                    </div>
                                    <div className="admin-panel">
                                        <table className="admin-table">
                                            <thead>
                                                <tr>
                                                    <th style={{ width: '34px' }}></th>
                                                    <th>H盻・Tﾃｪn</th>
                                                    <th>Quﾃｪ quﾃ｡n / Ngﾃnh</th>
                                                    <th style={{ textAlign: 'right' }}>Thao tﾃ｡c</th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                {availableCandidates.length === 0 ? (
                                                    <tr><td colSpan="4" style={{ textAlign: 'center', padding: '2.5rem', color: '#cbd5e1', fontSize: '0.8rem' }}>Khﾃｴng cﾃｳ 盻ｩng viﾃｪn nﾃo 盻・tr蘯｡ng thﾃ｡i Ch盻・ph盻熟g v蘯･n.</td></tr>
                                                ) : availableCandidates.map(c => (
                                                    <tr key={c.id}>
                                                        <td style={{ padding: '0.4rem 0.4rem' }}>
                                                            <div style={{ width: '30px', height: '30px', borderRadius: '50%', overflow: 'hidden', border: '1px solid #e2e8f0', background: '#f8fafc', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                                                {c.anh_ho_so
                                                                    ? <img src={c.anh_ho_so} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                                                                    : <span className="material-icons-outlined" style={{ fontSize: '16px', color: '#cbd5e1' }}>person</span>
                                                                }
                                                            </div>
                                                        </td>
                                                        <td>
                                                            <div style={{ fontWeight: '700', fontSize: '0.82rem', color: '#0f172a' }}>{c.ho_ten}</div>
                                                            <div style={{ fontSize: '0.67rem', color: '#94a3b8' }}>{age(c.ngay_sinh)} tu盻品</div>
                                                        </td>
                                                        <td style={{ fontSize: '0.78rem', color: '#64748b' }}>
                                                            <div>{c.que_quan || '窶・}</div>
                                                            <div style={{ fontSize: '0.67rem', color: '#94a3b8' }}>{c.nganh_nghe_mong_muon || 'Lﾄ娠T'}</div>
                                                        </td>
                                                        <td style={{ textAlign: 'right' }}>
                                                            <button onClick={() => handleAddCandidate(c)} className="admin-btn-primary" style={{ height: '28px', fontSize: '0.7rem', padding: '0 0.6rem' }}>
                                                                <span className="material-icons-outlined" style={{ fontSize: '13px' }}>add</span>Ch盻肱
                                                            </button>
                                                        </td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            )}
                        </div>
                    </>)}
                </div>
            </div>
        </div>
    )
}

import { useEffect, useState } from 'react'
import { useParams } from 'react-router-dom'
import { supabase } from '../../supabaseClient'
import {
    getAge, mapRelation, mapVision, mapHand, mapMarital,
    mapJapaneseLevel, mapYesNoShort, mapEducationShort
} from '../../utils/printHelpers'

export default function PrintCandidateList() {
    const { id } = useParams() // Order ID
    const [order, setOrder] = useState(null)
    const [candidates, setCandidates] = useState([])
    const [loading, setLoading] = useState(true)

    // Print Info
    const [printInfo, setPrintInfo] = useState({
        companyName: '',
        jobDescription: '',
        supervisingOrg: '',
        interviewDate: ''
    })

    useEffect(() => {
        const fetchData = async () => {
            try {
                // Fetch Order Info
                const { data: orderData, error: orderError } = await supabase
                    .from('don_hang')
                    .select('*')
                    .eq('id', id)
                    .single()

                if (orderError) throw orderError
                setOrder(orderData)
                setPrintInfo(prev => ({
                    ...prev,
                    interviewDate: orderData.ngay_tuyen_du_kien ? new Date(orderData.ngay_tuyen_du_kien).toISOString().split('T')[0] : ''
                }))

                // Fetch Candidates
                const { data: candidatesData, error: candidatesError } = await supabase
                    .from('lien_ket_don_hang_ho_so')
                    .select(`
                        id, sbd, created_at,
                        ho_so:ho_so_id ( 
                            *,
                            thong_tin_gia_dinh,
                            qua_trinh_hoc_tap,
                            kinh_nghiem_lam_viec
                        )
                    `)
                    .eq('don_hang_id', id)
                    .order('sbd', { ascending: true })

                if (candidatesError) throw candidatesError
                setCandidates(candidatesData || [])

            } catch (error) {
                console.error('Error:', error)
                alert(`Error: ${error.message}`)
            } finally {
                setLoading(false)
            }
        }
        if (id) fetchData()
    }, [id])

    useEffect(() => {
        if (!loading && order) document.title = `List_${order.ten_don_hang}_JP`
    }, [loading, order])

    // --- Helpers using imported utils ---

    const getFamilySummary = (familyArr) => {
        if (!Array.isArray(familyArr) || familyArr.length === 0) return '---'
        const count = familyArr.length
        const relations = familyArr.map(m => mapRelation(m.quan_he)).join(', ')
        return `${count}蜷・(${relations})`
    }

    const getEducationSummary = (eduArr) => {
        if (!Array.isArray(eduArr) || eduArr.length === 0) return '---'
        // Find highest degree
        const levels = eduArr.map(e => e.bang_cap)
        if (levels.some(l => l.includes('ﾄ雪ｺ｡i H盻皇'))) return '螟ｧ蜊・
        if (levels.some(l => l.includes('Cao ﾄ雪ｺｳng'))) return '遏ｭ螟ｧ蜊・
        if (levels.some(l => l.includes('Trung C蘯･p'))) return '蟆る摩蜊・
        if (levels.some(l => l.includes('C蘯･p 3') || l.includes('THPT'))) return '鬮伜穀'
        if (levels.some(l => l.includes('C蘯･p 2') || l.includes('THCS'))) return '荳ｭ蜊・
        return '---'
    }


    // --- Pagination Logic ---
    const PAGE_SIZE_FIRST = 4 // Trang 1 ch盻ｩa 4 ngﾆｰ盻拱 (vﾃｬ cﾃｳ Header)
    const PAGE_SIZE_OTHER = 5 // Trang sau ch盻ｩa 5 ngﾆｰ盻拱

    const pages = []
    if (candidates.length > 0) {
        pages.push(candidates.slice(0, PAGE_SIZE_FIRST))
        let current = PAGE_SIZE_FIRST
        while (current < candidates.length) {
            pages.push(candidates.slice(current, current + PAGE_SIZE_OTHER))
            current += PAGE_SIZE_OTHER
        }
    }

    if (loading) return <div className="text-center p-10">隱ｭ縺ｿ霎ｼ縺ｿ荳ｭ...</div>
    if (!order) return <div className="text-center p-10 text-red-500">豕ｨ譁・′隕九▽縺九ｊ縺ｾ縺帙ｓ!</div>

    return (
        <div className="bg-gray-100 min-h-screen p-8 print:p-0 font-sans text-black">
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Noto+Sans+JP:wght@300;400;500;700&display=swap');
                @media print {
                    @page { size: A4 portrait; margin: 0; }
                    body { font-family: 'Noto Sans JP', sans-serif !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
                    .print-page { 
                        break-after: page; 
                        box-shadow: none !important; 
                        margin: 0 !important; 
                        border: none !important;
                        
                        /* Fit to page */
                        height: 297mm;
                        overflow: hidden !important;
                        zoom: 0.95;
                        page-break-inside: avoid;
                    }
                    .no-print { display: none !important; }
                }
                
                @media screen {
                    body {
                        min-width: 220mm; /* Desktop layout on mobile */
                        overflow-x: auto;
                    }
                    .print-page {
                        width: 210mm !important;
                        min-width: 210mm !important;
                    }
                }

                .print-page {
                    background: white; width: 210mm; height: 297mm; margin: 0 auto 20px auto; 
                    box-shadow: 0 0 10px rgba(0,0,0,0.1); overflow: hidden; position: relative;
                }
                .input-underline { border-bottom: 1px dashed #9ca3af; width: 100%; outline: none; background: transparent; padding: 0 4px; font-weight: 500; color: #1f2937; }
                .input-underline:focus { border-bottom: 2px solid #2563eb; }
                
                .info-table td { padding: 5px 6px; border: 1px solid #d1d5db; vertical-align: middle; }
                .label-cell { background-color: #f3f4f6; font-weight: bold; color: #374151; width: 14%; font-size: 10px; }
                .value-cell { font-weight: 500; font-size: 11px; color: #111827; }
            `}</style>

            <div className="fixed top-4 right-4 no-print flex gap-2 z-50">
                <button onClick={() => window.print()} className="bg-blue-600 text-white px-4 py-2 rounded shadow hover:bg-blue-700 font-bold flex items-center gap-2">
                    <span className="material-icons-outlined">print</span> Print
                </button>
            </div>

            {pages.length === 0 && <div className="text-center p-10">蛟呵｣懆・′縺・∪縺帙ｓ縲・/div>}

            {pages.map((group, pageIndex) => (
                <div key={pageIndex} className="print-page">
                    <div className="h-full flex flex-col box-border px-[12mm] pb-[10mm]" style={{ paddingTop: pageIndex === 0 ? '10mm' : '25mm' }}>

                        {/* HEADER - Only on Page 1 */}
                        {pageIndex === 0 && (
                            <>
                                <div className="text-center mb-4">
                                    <h1 className="text-2xl font-bold uppercase text-gray-800 border-b-2 border-gray-800 inline-block pb-1">髱｢ 謗･ 蛟・陬・閠・繝ｪ 繧ｹ 繝・/h1>
                                </div>
                                <div className="grid grid-cols-2 gap-x-8 gap-y-2 mb-4 text-sm px-2">
                                    <div className="flex items-center">
                                        <span className="min-w-[80px] font-bold text-gray-700">蜿怜・莨∵･ｭ:</span>
                                        <input className="input-underline" value={printInfo.companyName} onChange={e => setPrintInfo({ ...printInfo, companyName: e.target.value })} />
                                    </div>
                                    <div className="flex items-center">
                                        <span className="min-w-[80px] font-bold text-gray-700">閨ｷ遞ｮ:</span>
                                        <input className="input-underline" value={printInfo.jobDescription} onChange={e => setPrintInfo({ ...printInfo, jobDescription: e.target.value })} />
                                    </div>
                                    <div className="flex items-center">
                                        <span className="min-w-[80px] font-bold text-gray-700">逶｣逅・屮菴・</span>
                                        <input className="input-underline" value={printInfo.supervisingOrg} onChange={e => setPrintInfo({ ...printInfo, supervisingOrg: e.target.value })} />
                                    </div>
                                    <div className="flex items-center">
                                        <span className="min-w-[80px] font-bold text-gray-700">驕ｸ閠・律:</span>
                                        <input type="date" className="input-underline" value={printInfo.interviewDate} onChange={e => setPrintInfo({ ...printInfo, interviewDate: e.target.value })} />
                                    </div>
                                </div>
                            </>
                        )}

                        {/* LIST */}
                        <div className="space-y-5 flex-1">
                            {group.map((item, index) => {
                                const c = item.ho_so || {}
                                const globalIndex = (pageIndex === 0 ? 0 : PAGE_SIZE_FIRST) + (pageIndex > 1 ? (pageIndex - 1) * PAGE_SIZE_OTHER : 0) + index + 1
                                return (
                                    <div key={item.id} className="border border-gray-400 p-1.5 flex gap-2 items-start shadow-sm rounded-sm">
                                        {/* Avatar Col */}
                                        <div className="flex flex-col items-center gap-1 w-[30mm] shrink-0 border-r border-gray-200 pr-1.5">
                                            <div className="text-2xl font-black text-gray-400">{item.sbd ? item.sbd.toString().padStart(2, '0') : globalIndex.toString().padStart(2, '0')}</div>
                                            <div className="w-[28mm] h-[36mm] border border-gray-200 bg-gray-50 flex items-center justify-center overflow-hidden">
                                                {c.anh_ho_so ? <img src={c.anh_ho_so} className="w-full h-full object-cover" /> : <span className="text-[10px] text-gray-400">蜀咏悄辟｡</span>}
                                            </div>
                                        </div>
                                        {/* Info Col */}
                                        <div className="flex-1 min-w-0">
                                            <div className="flex justify-between items-baseline border-b border-gray-300 pb-0.5 mb-1.5">
                                                <div>
                                                    <span className="text-base font-bold uppercase text-blue-900 mr-2">{c.ho_ten}</span>
                                                    {c.nickname && <span className="text-xs text-gray-400 ml-3">Nickname: <span className="text-sm font-bold text-blue-900">{c.nickname}</span></span>}
                                                </div>
                                                <div className="text-xs font-bold text-gray-700">
                                                    {getAge(c.ngay_sinh)}豁ｳ <span className="font-normal text-gray-500">({c.ngay_sinh ? new Date(c.ngay_sinh).getFullYear() : ''})</span>
                                                </div>
                                            </div>
                                            <table className="w-full info-table border-collapse">
                                                <tbody>
                                                    <tr>
                                                        <td className="label-cell">蜃ｺ霄ｫ</td><td className="value-cell" colSpan={3}>{c.que_quan}</td>
                                                        <td className="label-cell">蟀壼ｧｻ</td><td className="value-cell w-[16%]">{mapMarital(c.hon_nhan)}</td>
                                                    </tr>
                                                    <tr>
                                                        <td className="label-cell">菴捺ｼ</td>
                                                        <td className="value-cell" colSpan={3}>
                                                            {c.chieu_cao}cm / {c.can_nang}kg <span className="text-gray-300 mx-1">|</span> {c.nhom_mau} <span className="text-gray-300 mx-1">|</span> {mapHand(c.tay_thuan)}
                                                        </td>
                                                        <td className="label-cell">隕門鴨</td><td className="value-cell">{mapVision(c.thi_luc_trai)} / {mapVision(c.thi_luc_phai)}</td>
                                                    </tr>
                                                    <tr>
                                                        <td className="label-cell">蟄ｦ豁ｴ</td><td className="value-cell" colSpan={3}>{getEducationSummary(c.qua_trinh_hoc_tap)}</td>
                                                        <td className="label-cell">譌･譛ｬ隱・/td><td className="value-cell">{mapJapaneseLevel(c.trinh_do_tieng_nhat)}</td>
                                                    </tr>
                                                    {/* Row removed: 邨梧ｭｴ */}
                                                    <tr>
                                                        <td className="label-cell">螳ｶ譌・/td><td className="value-cell" colSpan={5}>{getFamilySummary(c.thong_tin_gia_dinh)}</td>
                                                    </tr>
                                                    <tr>
                                                        <td className="label-cell">蛯呵・/td>
                                                        <td className="value-cell text-[9px]" colSpan={5}>
                                                            <span className={`mr-4 ${mapYesNoShort(c.xam_hinh) === '譛・ ? 'text-red-600 font-bold' : 'text-gray-500'}`}>
                                                                蛻ｺ髱・ {mapYesNoShort(c.xam_hinh)}
                                                            </span>
                                                            <span className={`mr-4 ${mapYesNoShort(c.hut_thuoc) === '譛・ ? 'text-red-600 font-bold' : 'text-gray-500'}`}>
                                                                蝟ｫ辣・ {mapYesNoShort(c.hut_thuoc)}
                                                            </span>
                                                            <span className={`${mapYesNoShort(c.mu_mau) === '譛・ ? 'text-red-600 font-bold' : 'text-gray-500'}`}>
                                                                濶ｲ逶ｲ: {mapYesNoShort(c.mu_mau)}
                                                            </span>
                                                        </td>
                                                    </tr>
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                )
                            })}
                        </div>

                        <div className="text-right text-[10px] text-gray-400 mt-2">
                            繝壹・繧ｸ {pageIndex + 1}/{pages.length}
                        </div>
                    </div>
                </div>
            ))}
        </div>
    )
}
